esqlQuery.esql:
FROM logs-openai.*
| WHERE event.dataset IN ("openai.rate_limits", "openai.completions", "openai.embeddings", "openai.moderations")
// audio_speeches, audio_transcriptions, and images contribute no tokens (RPM-only streams) — their exclusion here is intentional
| EVAL project_id = COALESCE(openai.rate_limits.project_id, openai.base.project_id)
// Normalize dated model snapshots (e.g. gpt-image-1-2025-04-23, omni-moderation-2024-09-26)
// to their base family by stripping a trailing -YYYY-MM-DD. OpenAI's usage API reports per
// dated snapshot, while rate_limits often lists only the base name, so without this the usage
// row finds no matching limit and is dropped from the headroom join.
| EVAL model = REPLACE(COALESCE(openai.rate_limits.model, openai.base.model), "-[0-9]{4}-[0-9]{2}-[0-9]{2}$", "")
// usage_tokens is normalized by each usage pipeline into openai.base.usage_tokens,
// so this rule resolves even when some usage streams have no data.
| EVAL usage_tokens = COALESCE(openai.base.usage_tokens, 0)
// Peak 1-minute usage per project and model, joined to the configured limit
| STATS
    tpm_used_minute = SUM(usage_tokens),
    tpm_limit = MAX(openai.rate_limits.max_tokens_per_1_minute)
  BY project_id, model, minute = BUCKET(@timestamp, 1 minute)
| STATS
    peak_tpm_used = MAX(tpm_used_minute),
    tpm_limit = MAX(tpm_limit)
  BY project_id, model
| WHERE tpm_limit > 0
// TO_DOUBLE avoids integer division (otherwise utilization is always 0 until usage exceeds the limit)
| EVAL tpm_utilization = TO_DOUBLE(peak_tpm_used) / tpm_limit
// 80% threshold — edit this value to tune sensitivity
| WHERE tpm_utilization >= 0.8
| EVAL alert_key = CONCAT(TO_STRING(project_id), "::", TO_STRING(model))
// Highest-utilization groups first so that if the cap is ever hit the worst offenders
// still alert. The cap is aligned with the alerting max-alerts circuit breaker
// (xpack.alerting.rules.run.alerts.max, default 1000): Kibana always appends its own
// | LIMIT <max-alerts> and ES applies the smallest LIMIT, so anything below 1000 here
// would silently drop breaching groups with no truncation warning. At 1000 the cap
// coincides with the circuit breaker, which does surface a truncation warning.
| SORT tpm_utilization DESC
| LIMIT 1000
